(function () {
  'use strict';
  // 1 cubic cm = 0.001 litres
  // 1 litre = 0.219969 UK gallons
  // 1 litre = 0.264172 US gallons
  const L_PER_CM3 = 0.001;
  const UK_GAL_PER_L = 0.219969;
  const US_GAL_PER_L = 0.264172;
  // Convert any input value to centimetres
  function toCm(value, unit) {
    switch (unit) {
      case 'cm': return value;
      case 'mm': return value / 10;
      case 'in': return value * 2.54;
      default: return value;
    }
  }
  function rectangleVolumeL(L_cm, W_cm, H_cm) {
    return (L_cm * W_cm * H_cm) * L_PER_CM3;
  }
  function cylinderVolumeL(diameter_cm, height_cm) {
    const r = diameter_cm / 2;
    return (Math.PI * r * r * height_cm) * L_PER_CM3;
  }
  function sphereVolumeL(diameter_cm) {
    const r = diameter_cm / 2;
    return ((4 / 3) * Math.PI * Math.pow(r, 3)) * L_PER_CM3;
  }
  function stockingInches(usGallons) {
    return Math.max(0, Math.round(usGallons));
  }
  const $ = (sel, root = document) => root.querySelector(sel);
  const $$ = (sel, root = document) => Array.from(root.querySelectorAll(sel));
  const state = {
    shape: 'rectangle',  // rectangle | cylinder | sphere
    unit: 'cm',          // cm | mm | in
    inputs: {},          // per-shape numeric inputs
    glassMm: 0,          // glass thickness in mm (optional)
    result: null         // last computed result object
  };
  function init() {
    const calc = $('#tank-calculator');
    if (!calc) return; // not on this page
    bindShapeTabs();
    bindUnitPills();
    bindCalculate();
    bindReset();
    bindExports();
    bindI18nVoice();
    renderShape();        // initial shape panel
    updateUnitTags();     // initial unit labels
  }
  function bindI18nVoice() {
    if (!window.FishhearI18N) return;
    const ui = window.FishhearI18N.buildControlRow('i18n-voice-mount', () => {
      if (state.result) renderResults(state.result); // re-render labels in new language
    });
    if (!ui) return;
    ui.speakBtn.addEventListener('click', () => {
      if (!state.result) { flashError('Calculate a result first.'); return; }
      window.FishhearI18N.speak(buildSpokenSentence(state.result));
    });
  }
  function buildSpokenSentence(r) {
    const I = window.FishhearI18N;
    if (!I) return '';
    const n = (v, d) => I.formatNumber(v, d);
    return `${I.t('tank_holds')} ${n(r.realFillL, 1)} ${I.t('litres')} — ${n(r.ukGal, 1)} ${I.t('uk_gal')}, ${n(r.usGal, 1)} ${I.t('us_gal')}.`;
  }
  function bindShapeTabs() {
    $$('.shape-tab').forEach(tab => {
      tab.addEventListener('click', () => {
        $$('.shape-tab').forEach(t => t.classList.remove('active'));
        tab.classList.add('active');
        state.shape = tab.dataset.shape;
        renderShape();
        clearResults();
      });
    });
  }
  function renderShape() {
    $$('.shape-panel').forEach(panel => {
      panel.style.display = panel.dataset.shape === state.shape ? 'block' : 'none';
    });
  }
  function bindUnitPills() {
    $$('.unit-pill').forEach(pill => {
      pill.addEventListener('click', () => {
        $$('.unit-pill').forEach(p => p.classList.remove('active'));
        pill.classList.add('active');
        state.unit = pill.dataset.unit;
        updateUnitTags();
      });
    });
  }
  function updateUnitTags() {
    const label = state.unit === 'in' ? 'in' : state.unit;
    $$('.unit-tag[data-tag="dim"]').forEach(el => { el.textContent = `(${label})`; });
    $$('.unit-tag[data-tag="glass"]').forEach(el => { el.textContent = `(mm)`; });
  }
  function bindCalculate() {
    $('#btn-calculate').addEventListener('click', calculate);
    // Allow Enter key inside any input to fire calculation
    $$('#tank-calculator input[type="number"]').forEach(inp => {
      inp.addEventListener('keydown', e => {
        if (e.key === 'Enter') { e.preventDefault(); calculate(); }
      });
    });
  }
  function readInput(id) {
    const el = document.getElementById(id);
    if (!el) return NaN;
    const v = parseFloat(el.value);
    return isNaN(v) ? NaN : v;
  }
  function calculate() {
    const unit = state.unit;
    let grossL = 0;       // gross volume (litres) before glass deduction
    let valid = false;
    let dims = {};
    if (state.shape === 'rectangle') {
      const L = readInput('rect-length');
      const W = readInput('rect-width');
      const H = readInput('rect-height');
      if (!isFinite(L) || !isFinite(W) || !isFinite(H) || L <= 0 || W <= 0 || H <= 0) {
        flashError('Please enter valid length, width, and height.');
        return;
      }
      const Lcm = toCm(L, unit), Wcm = toCm(W, unit), Hcm = toCm(H, unit);
      grossL = rectangleVolumeL(Lcm, Wcm, Hcm);
      dims = { L, W, H };
      valid = true;
    } else if (state.shape === 'cylinder') {
      const D = readInput('cyl-diameter');
      const H = readInput('cyl-height');
      if (!isFinite(D) || !isFinite(H) || D <= 0 || H <= 0) {
        flashError('Please enter valid diameter and height.');
        return;
      }
      const Dcm = toCm(D, unit), Hcm = toCm(H, unit);
      grossL = cylinderVolumeL(Dcm, Hcm);
      dims = { D, H };
      valid = true;
    } else if (state.shape === 'sphere') {
      const D = readInput('sph-diameter');
      if (!isFinite(D) || D <= 0) {
        flashError('Please enter a valid diameter.');
        return;
      }
      const Dcm = toCm(D, unit);
      grossL = sphereVolumeL(Dcm);
      dims = { D };
      valid = true;
    }
    if (!valid) return;
    // Optional glass thickness compensation (subtracts an approximate inner-cavity reduction).
    // For rectangle: thickness reduces each external dimension by 2 * thickness.
    // For others we only mention water-fill as a separate output.
    const glassMm = parseFloat($('#glass-thickness').value);
    let netL = grossL;
    if (state.shape === 'rectangle' && isFinite(glassMm) && glassMm > 0) {
      const t_cm = glassMm / 10;
      const Lcm = toCm(dims.L, unit) - 2 * t_cm;
      const Wcm = toCm(dims.W, unit) - 2 * t_cm;
      const Hcm = toCm(dims.H, unit) - t_cm; // bottom only, no lid
      if (Lcm > 0 && Wcm > 0 && Hcm > 0) {
        netL = rectangleVolumeL(Lcm, Wcm, Hcm);
      }
    }
    // 90% fill rule for actual water held (substrate, decor, surface gap)
    const realFillL = netL * 0.90;
    const ukGal = realFillL * UK_GAL_PER_L;
    const usGal = realFillL * US_GAL_PER_L;
    const grossUkGal = grossL * UK_GAL_PER_L;
    const grossUsGal = grossL * US_GAL_PER_L;
    state.result = {
      shape: state.shape,
      unit,
      dims,
      glassMm: isFinite(glassMm) ? glassMm : 0,
      grossL, netL, realFillL,
      grossUkGal, grossUsGal, ukGal, usGal,
      stockingInches: stockingInches(usGal),
      timestamp: new Date()
    };
    renderResults(state.result);
  }
  function flashError(msg) {
    const empty = $('#result-empty');
    const filled = $('#result-filled');
    if (empty) empty.style.display = 'grid';
    if (filled) filled.style.display = 'none';
    const note = $('#result-error');
    if (note) {
      note.textContent = msg;
      note.style.display = 'block';
      setTimeout(() => { note.style.display = 'none'; }, 3500);
    }
  }
  function renderResults(r) {
    const empty = $('#result-empty');
    const filled = $('#result-filled');
    if (empty) empty.style.display = 'none';
    if (filled) filled.style.display = 'block';
    const I = window.FishhearI18N;
    const litresLabel = I ? I.t('litres') : 'L';
    const ukLabel = I ? I.t('uk_gal') : 'UK gal';
    const usLabel = I ? I.t('us_gal') : 'US gal';
    const fmtN = (v, d) => I ? I.formatNumber(v, d) : fmt(v);
    $('#out-litres').innerHTML = `${fmtN(r.realFillL, 1)}<span class="unit">${litresLabel === 'litres' ? 'L' : litresLabel}</span>`;
    $('#out-uk').innerHTML = `${fmtN(r.ukGal, 1)}<span class="unit">${ukLabel}</span>`;
    $('#out-us').innerHTML = `${fmtN(r.usGal, 1)}<span class="unit">${usLabel}</span>`;
    $('#out-gross').innerHTML = `${fmtN(r.grossL, 1)}<span class="unit">${litresLabel === 'litres' ? 'L' : litresLabel}</span>`;
    $('#out-stocking').textContent = I
      ? `≈ ${r.stockingInches} ${I.t('inches_fish')}`
      : `≈ ${r.stockingInches} inches of small community fish (guideline only — research each species' adult size and temperament before stocking).`;
    // Animate the little tank fill svg
    const fill = $('#tank-fill-bar');
    if (fill) {
      const ratio = Math.min(1, r.realFillL / 250); // normalised against a 250L visual
      fill.style.height = (60 + ratio * 30).toFixed(1) + '%';
    }
  }
  function clearResults() {
    const empty = $('#result-empty');
    const filled = $('#result-filled');
    if (empty) empty.style.display = 'grid';
    if (filled) filled.style.display = 'none';
    state.result = null;
  }
  function fmt(n) {
    if (!isFinite(n)) return '—';
    if (n >= 1000) return n.toFixed(0);
    if (n >= 100) return n.toFixed(1);
    return n.toFixed(2);
  }
  function bindReset() {
    $('#btn-reset').addEventListener('click', () => {
      $$('#tank-calculator input[type="number"]').forEach(inp => { inp.value = ''; });
      clearResults();
    });
  }
  function bindExports() {
    $('#btn-export-csv')?.addEventListener('click', exportCSV);
    $('#btn-export-print')?.addEventListener('click', () => window.print());
    $('#btn-export-copy')?.addEventListener('click', copyResult);
  }
  function exportCSV() {
    if (!state.result) { flashError('Calculate a result first.'); return; }
    const r = state.result;
    const rows = [
      ['Fishhear Tank Volume Report'],
      ['Generated', r.timestamp.toISOString()],
      ['Shape', r.shape],
      ['Unit', r.unit],
      ['Glass thickness (mm)', r.glassMm],
      [],
      ['Metric', 'Value'],
      ['Gross volume (L)', r.grossL.toFixed(2)],
      ['Gross volume (UK gal)', r.grossUkGal.toFixed(2)],
      ['Gross volume (US gal)', r.grossUsGal.toFixed(2)],
      ['Realistic water fill (L, 90%)', r.realFillL.toFixed(2)],
      ['Realistic water fill (UK gal)', r.ukGal.toFixed(2)],
      ['Realistic water fill (US gal)', r.usGal.toFixed(2)],
      ['Stocking guideline (inches of fish)', r.stockingInches]
    ];
    const csv = rows.map(row => row.map(cell => {
      const s = String(cell ?? '');
      return /[",\n]/.test(s) ? '"' + s.replace(/"/g, '""') + '"' : s;
    }).join(',')).join('\n');
    const blob = new Blob([csv], { type: 'text/csv;charset=utf-8;' });
    const url = URL.createObjectURL(blob);
    const a = document.createElement('a');
    a.href = url;
    a.download = `fishhear-tank-volume-${Date.now()}.csv`;
    document.body.appendChild(a);
    a.click();
    document.body.removeChild(a);
    URL.revokeObjectURL(url);
  }
  async function copyResult() {
    if (!state.result) { flashError('Calculate a result first.'); return; }
    const r = state.result;
    const I = window.FishhearI18N;
    const txt = `Fishhear Tank Volume Report
Shape: ${r.shape}
Gross volume: ${r.grossL.toFixed(1)} L (${r.grossUkGal.toFixed(1)} UK gal / ${r.grossUsGal.toFixed(1)} US gal)
Realistic water fill (90%): ${r.realFillL.toFixed(1)} L (${r.ukGal.toFixed(1)} UK gal / ${r.usGal.toFixed(1)} US gal)
Stocking guideline: ~${r.stockingInches} inches of small community fish${I ? '\n\n' + buildSpokenSentence(r) : ''}`;
    if (I) {
      await I.copyText(txt, $('#btn-export-copy'));
      return;
    }
    try {
      await navigator.clipboard.writeText(txt);
      const btn = $('#btn-export-copy');
      const original = btn.innerHTML;
      btn.innerHTML = '✓ Copied';
      setTimeout(() => { btn.innerHTML = original; }, 1800);
    } catch (e) {
      flashError('Could not copy. Your browser blocked clipboard access.');
    }
  }
  /* ---------- Boot ---------- */
  if (document.readyState === 'loading') {
    document.addEventListener('DOMContentLoaded', init);
  } else {
    init();
  }
})();